def set_budget(budgets, category, amount):
    """Set the budget for a category and return the stored amount."""
    budgets[category] = float(amount)
    return budgets[category]


def over_budget_categories(records, budgets):
    """Return the set of categories whose summed distance exceeds their budget.

    A category with no budget is never over; hitting the budget exactly
    is not over — only a strictly greater total flags it.
    """
    over = set()
    for category, _count, subtotal in category_report(records):
        budget = budgets.get(category)
        if budget is not None and subtotal > budget:
            over.add(category)
    return over


